/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const N = nums.length;

    // 1. Build Adjacency Matrix
    const adj = Array(N).fill(0).map(() => Array(N).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
    }

    let count = 0;

    // Iterate through all non-empty subsets (masks from 1 to 2^N - 1)
    const totalMasks = 1 << N;
    for (let mask = 1; mask < totalMasks; mask++) {

        let sum = 0;
        let subsetSize = 0;

        // 2. Calculate Sum and Size
        for (let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
                subsetSize++;
            }
        }

        // 3. Check Parity Condition
        if (sum % 2 !== 0) {
            continue;
        }

        // 4. Check Connectivity Condition
        let isConnected = true;

        if (subsetSize > 1) {
            // Find a starting node (the smallest index in the subset)
            let startNode = -1;
            for (let i = 0; i < N; i++) {
                if ((mask >> i) & 1) {
                    startNode = i;
                    break;
                }
            }

            // BFS for connectivity check
            const queue = [startNode];
            // Using a boolean array for visited status within this subset check
            const visited = new Array(N).fill(false);
            visited[startNode] = true;
            let visitedCount = 1;

            let head = 0;
            while (head < queue.length) {
                const u = queue[head++];

                for (let v = 0; v < N; v++) {
                    // Check if v is a neighbor of u AND v is in the subset AND v is not visited
                    if (adj[u][v] && ((mask >> v) & 1) && !visited[v]) {
                        visited[v] = true;
                        visitedCount++;
                        queue.push(v);
                    }
                }
            }

            if (visitedCount !== subsetSize) {
                isConnected = false;
            }
        }
        // If subsetSize == 1, it is always connected (isConnected remains true).

        // 5. Count if both conditions met
        if (isConnected) {
            count++;
        }
    }

    return count;
}

