import java.util.LinkedList;
import java.util.Queue;

public class Solution {
    public static long solve(long[] nums, long[][] edges) {
        int N = nums.length;

        // 1. Build Adjacency Matrix
        boolean[][] adj = new boolean[N][N];
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            adj[u][v] = true;
            adj[v][u] = true;
        }

        long count = 0;

        // Iterate through all non-empty subsets (masks from 1 to 2^N - 1)
        int totalMasks = 1 << N;
        for (int mask = 1; mask < totalMasks; mask++) {

            long sum = 0;
            int subsetSize = 0;

            // 2. Calculate Sum and Size
            for (int i = 0; i < N; i++) {
                if (((mask >> i) & 1) == 1) {
                    sum += nums[i];
                    subsetSize++;
                }
            }

            // 3. Check Parity Condition
            if (sum % 2 != 0) {
                continue;
            }

            // 4. Check Connectivity Condition
            boolean isConnected = true;

            if (subsetSize > 1) {
                // Find a starting node (the smallest index in the subset)
                int startNode = -1;
                for (int i = 0; i < N; i++) {
                    if (((mask >> i) & 1) == 1) {
                        startNode = i;
                        break;
                    }
                }

                // BFS for connectivity check
                Queue<Integer> queue = new LinkedList<>();
                boolean[] visited = new boolean[N];

                queue.add(startNode);
