                }
            }

            if (visitedCount != subsetSize) {
                isConnected = false;
            }
        }
        // If subsetSize == 1, it is always connected (isConnected remains true).

        // 5. Count if both conditions met
        if (isConnected) {
            count++;
        }
    }

    return count;
}

